    {"title":"Toxicity","artist":"System of a Down","album":"Toxicity","release_year":2001,"mode":"bass","part_type":"bassline","part_label":"driving bassline","tone_type":"bass_drive","genre":"alternative metal","tone_category":"bass","difficulty":"intermediate","original_guitar":"Fender Jazz Bass","original_amp":"Ampeg SVT","original_cab":"Ampeg 8x10","original_pickup":"Fender Jazz Bass single-coil pickups","confidence":80,"era":"2000s"},
