    {"title":"Aerials","artist":"System of a Down","album":"Toxicity","release_year":2001,"mode":"guitar","part_type":"solo","part_label":"lead solo break","tone_type":"high_gain","genre":"alternative metal","tone_category":"lead","difficulty":"advanced","original_guitar":"Gibson SG Standard","original_amp":"Marshall JCM800","original_cab":"Marshall 4x12 (Celestion Vintage 30s)","original_pickup":"Gibson humbuckers","confidence":81,"era":"2000s"},
    {"title":"Aerials","artist":"System of a Down","album":"Toxicity","release_year":2001,"mode":"bass","part_type":"bassline","part_label":"main bassline","tone_type":"bass_drive","genre":"alternative metal","tone_category":"bass","difficulty":"intermediate","original_guitar":"Fender Jazz Bass","original_amp":"Ampeg SVT","original_cab":"Ampeg 8x10","original_pickup":"Fender Jazz Bass single-coil pickups","confidence":79,"era":"2000s"},
    {"title":"Figure It Out","artist":"Royal Blood","album":"Royal Blood","release_year":2014,"mode":"guitar","part_type":"riff","part_label":"main riff","tone_type":"fuzz","genre":"alternative rock","tone_category":"distortion","difficulty":"intermediate","original_guitar":"Fender Jazz Bass (through guitar amps)","original_amp":"Fender Super Bassman","original_cab":"Fender 4x12","original_pickup":"Fender Jazz Bass single-coil pickups","confidence":80,"era":"2010s"},
    {"title":"Figure It Out","artist":"Royal Blood","album":"Royal Blood","release_year":2014,"mode":"guitar","part_type":"solo","part_label":"guitar solo","tone_type":"fuzz","genre":"alternative rock","tone_category":"lead","difficulty":"advanced","original_guitar":"Fender Jazz Bass (through guitar amps)","original_amp":"Fender Super Bassman","original_cab":"Fender 4x12","original_pickup":"Fender Jazz Bass single-coil pickups","confidence":78,"era":"2010s"},
    {"title":"Figure It Out","artist":"Royal Blood","album":"Royal Blood","release_year":2014,"mode":"bass","part_type":"bassline","part_label":"driving bassline","tone_type":"bass_drive","genre":"alternative rock","tone_category":"bass","difficulty":"intermediate","original_guitar":"Fender Jazz Bass","original_amp":"Fender Super Bassman","original_cab":"Fender 4x12","original_pickup":"Fender Jazz Bass single-coil pickups","confidence":82,"era":"2010s"}
  ]
  $tone_profiles$::jsonb) as p(
    title text, artist text, album text, release_year integer,
    mode text, part_type text, part_label text, tone_type text,
    genre text, tone_category text, difficulty text,
    original_guitar text, original_amp text, original_cab text, original_pickup text,
    confidence integer, era text
  )
),
normalized_seed as (
  select *,
    lower(trim(both '-' from regexp_replace(artist, '[^a-zA-Z0-9]+', '-', 'g'))) as artist_slug,
    lower(trim(both '-' from regexp_replace(title, '[^a-zA-Z0-9]+', '-', 'g'))) as song_slug
  from profile_seed
),
artist_rows as (
  select distinct artist as name, artist_slug as slug from normalized_seed
),
upsert_artists as (
  insert into public.artists (name, slug, country, search_text, is_active)
  select name, slug, 'Global', concat_ws(' ', name, 'tone database artist'), true
  from artist_rows
  on conflict (slug) do update set
    name = excluded.name, search_text = excluded.search_text, is_active = true, updated_at = now()
  returning id, slug, name
),
song_rows as (
  select distinct on (artist_slug, song_slug) title, artist, artist_slug, song_slug, album, release_year, era
  from normalized_seed order by artist_slug, song_slug, confidence desc
),
upsert_songs as (
  insert into public.songs (artist_id, title, slug, album, release_year, search_text, is_active)
  select a.id, s.title, s.song_slug, s.album, s.release_year,
    concat_ws(' ', s.title, a.name, s.album, s.era, 'tone database'), true
  from song_rows s join upsert_artists a on a.slug = s.artist_slug
  on conflict (artist_id, slug) do update set
    title = excluded.title, album = excluded.album, release_year = excluded.release_year,
    search_text = excluded.search_text, is_active = true, updated_at = now()
  returning id, slug, title, artist_id
),
profile_source as (
  select s.id as song_id, n.*
  from normalized_seed n
  join upsert_artists a on a.slug = n.artist_slug
  join upsert_songs s on s.artist_id = a.id and s.slug = n.song_slug
)
insert into public.song_tone_profiles (
  song_id, song_title, artist_name, mode, part_type, part_label, tone_type,
  genre, tone_category, difficulty,
  original_guitar, original_amp, original_cab, original_pickup,
  original_effects, original_settings, adaptation_notes, playing_notes,
  source_summary, confidence, verification_status, search_text, is_public
)
select
  p.song_id, p.title, p.artist, p.mode, p.part_type, p.part_label, p.tone_type,
  p.genre, p.tone_category, p.difficulty,
  p.original_guitar, p.original_amp, p.original_cab, p.original_pickup,
  -- effects based on tone_type/part_type/genre
  case
    when p.mode = 'bass' then jsonb_build_array(
      jsonb_build_object('effect_type','compression','effect_name','bass compressor','placement','front','settings',jsonb_build_object('compression',4,'level',6)),
      jsonb_build_object('effect_type','eq','effect_name','bass EQ shaping','placement','post_gain','settings',jsonb_build_object('low',6,'mid',5,'high',4))
    )
    when p.tone_type = 'clean' then jsonb_build_array(
      jsonb_build_object('effect_type','compression','effect_name','light compressor','placement','front','settings',jsonb_build_object('compression',2,'level',5)),
      jsonb_build_object('effect_type','modulation','effect_name','subtle chorus','placement','post_gain','settings',jsonb_build_object('depth',2,'mix',2)),
      jsonb_build_object('effect_type','reverb','effect_name','spring reverb','placement','post_gain','settings',jsonb_build_object('mix',3,'decay',3))
    )
    when p.tone_type = 'crunch' then jsonb_build_array(
      jsonb_build_object('effect_type','drive','effect_name','mild overdrive','placement','front','settings',jsonb_build_object('gain',4,'tone',5,'level',6)),
      jsonb_build_object('effect_type','reverb','effect_name','room reverb','placement','post_gain','settings',jsonb_build_object('mix',2,'decay',3))
    )
    when p.part_type = 'solo' or p.part_type = 'lead' then jsonb_build_array(
      jsonb_build_object('effect_type','drive','effect_name','sustain boost','placement','front','settings',jsonb_build_object('gain',4,'tone',6,'level',6)),
      jsonb_build_object('effect_type','delay','effect_name','lead delay','placement','post_gain','settings',jsonb_build_object('mix',3,'time',4,'feedback',3)),
      jsonb_build_object('effect_type','reverb','effect_name','plate reverb','placement','post_gain','settings',jsonb_build_object('mix',2,'decay',4))
    )
    when p.tone_type = 'high_gain' then jsonb_build_array(
      jsonb_build_object('effect_type','gate','effect_name','tight noise gate','placement','front','settings',jsonb_build_object('threshold',6,'release',2)),
      jsonb_build_object('effect_type','drive','effect_name','tube screamer boost','placement','front','settings',jsonb_build_object('gain',2,'tone',7,'level',7)),
      jsonb_build_object('effect_type','eq','effect_name','post-amp EQ','placement','post_gain','settings',jsonb_build_object('low',5,'mid',6,'high',5))
    )
    when p.tone_type = 'fuzz' then jsonb_build_array(
      jsonb_build_object('effect_type','fuzz','effect_name','vintage fuzz','placement','front','settings',jsonb_build_object('fuzz',7,'tone',5,'level',6)),
      jsonb_build_object('effect_type','reverb','effect_name','spring reverb','placement','post_gain','settings',jsonb_build_object('mix',3,'decay',3))
    )
    else jsonb_build_array(
      jsonb_build_object('effect_type','gate','effect_name','noise gate','placement','front','settings',jsonb_build_object('threshold',5,'release',3)),
      jsonb_build_object('effect_type','drive','effect_name','overdrive boost','placement','front','settings',jsonb_build_object('gain',3,'tone',6,'level',6)),
      jsonb_build_object('effect_type','eq','effect_name','post-amp EQ','placement','post_gain','settings',jsonb_build_object('low',5,'mid',6,'high',5))
    )
  end,
  -- settings based on tone_type/genre
  case
    when p.mode = 'bass' and p.tone_type = 'bass_drive' then '{"gain":6,"bass":7,"mids":5,"treble":4,"presence":4,"reverb":0,"delay":0,"compression":5,"master":6}'::jsonb
    when p.mode = 'bass' then '{"gain":3,"bass":7,"mids":5,"treble":4,"presence":3,"reverb":0,"delay":0,"compression":5,"master":6}'::jsonb
    when p.tone_type = 'clean' then '{"gain":3,"bass":5,"mids":5,"treble":6,"presence":5,"reverb":2,"delay":0,"compression":3,"master":6}'::jsonb
    when p.tone_type = 'crunch' then '{"gain":5,"bass":5,"mids":6,"treble":6,"presence":5,"reverb":1,"delay":0,"compression":2,"master":6}'::jsonb
    when p.tone_type = 'high_gain' then '{"gain":8,"bass":5,"mids":6,"treble":6,"presence":7,"reverb":0,"delay":0,"compression":0,"master":5}'::jsonb
    when p.tone_type = 'fuzz' then '{"gain":7,"bass":6,"mids":4,"treble":5,"presence":4,"reverb":2,"delay":0,"compression":0,"master":5}'::jsonb
    when p.tone_type = 'acoustic' then '{"gain":2,"bass":5,"mids":6,"treble":7,"presence":5,"reverb":3,"delay":0,"compression":4,"master":6}'::jsonb
    when p.genre in ('metal','modern metal') then '{"gain":8,"bass":6,"mids":5,"treble":6,"presence":6,"reverb":1,"delay":0,"master":6}'::jsonb
    when p.genre = 'blues' then '{"gain":5,"bass":5,"mids":7,"treble":6,"presence":5,"reverb":2,"delay":1,"master":6}'::jsonb
    when p.part_type = 'solo' then '{"gain":7,"bass":5,"mids":7,"treble":6,"presence":6,"reverb":2,"delay":3,"master":6}'::jsonb
    else '{"gain":6,"bass":5,"mids":6,"treble":6,"presence":5,"reverb":1,"delay":0,"master":6}'::jsonb
  end,
  array['Catalog seed: use as starting point and refine by ear.','Match pickup and gain structure first, then adjust EQ for your cab.','If your amp is lower-gain, add a clean boost before increasing amp gain.'],
  array['Match the attack and dynamics of the original part.','Use less ambience live than on headphones.','For solos, favor sustain and mids over extra distortion.'],
  concat('Tone database seed profile for ', p.artist, ' - ', p.title, ' (', p.era, ')'),
  p.confidence,
  'starter_estimate',
  concat_ws(' ', p.title, p.artist, p.album, p.genre, p.tone_category, p.difficulty, p.era, p.part_label, p.tone_type, p.original_guitar, p.original_amp, p.original_pickup, 'tone database'),
  true
from profile_source p
on conflict (song_id, mode, part_type, tone_type, part_label) do update set
  song_title = excluded.song_title, artist_name = excluded.artist_name,
  genre = excluded.genre, tone_category = excluded.tone_category, difficulty = excluded.difficulty,
  original_guitar = excluded.original_guitar, original_amp = excluded.original_amp,
  original_cab = excluded.original_cab, original_pickup = excluded.original_pickup,
  original_effects = excluded.original_effects, original_settings = excluded.original_settings,
  adaptation_notes = excluded.adaptation_notes, playing_notes = excluded.playing_notes,
  source_summary = excluded.source_summary, confidence = excluded.confidence,
  search_text = excluded.search_text, updated_at = now();
